mapper.insert:
insert into batch.job_partition ( tenant_id, job_instance_id, partition_no, partition_key, partition_status, worker_group, worker_code, lease_expire_at, retry_count, business_key, idempotency_key, input_snapshot, output_summary, dry_run ) values ( #{tenantId}, #{jobInstanceId}, #{partitionNo}, #{partitionKey}, #{partitionStatus}, #{workerGroup}, #{workerCode}, #{leaseExpireAt}, #{retryCount}, #{businessKey}, #{idempotencyKey}, #{inputSnapshot,jdbcType=VARCHAR}::jsonb, #{outputSummary,jdbcType=VARCHAR}::jsonb,
#{dryRun} false
)

