mapper.update:
update batch.job_partition
set worker_code = #{workerCode},
    partition_status = #{toStatus},
    lease_expire_at = #{leaseExpireAt},
    started_at = coalesce(started_at, #{claimAt}),
    current_invocation_id = #{currentInvocationId},
    invocation_started_at = #{invocationStartedAt},
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and partition_status = #{fromStatus}
  and version = #{expectedVersion}

update batch.job_partition
set lease_expire_at = #{leaseExpireAt},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and worker_code = #{workerCode}
  and current_invocation_id = #{expectedInvocationId}

update batch.job_partition
set output_summary = #{outputSummary,jdbcType=VARCHAR}::jsonb,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

    and (current_invocation_id is null or current_invocation_id = #{expectedInvocationId})

update batch.job_partition
set input_snapshot = #{inputSnapshot,jdbcType=VARCHAR}::jsonb,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

    and (current_invocation_id is null or current_invocation_id = #{expectedInvocationId})

update batch.job_partition
set partition_status = #{partitionStatus},
    worker_code = case when #{partitionStatus} = #{runningStatus} then worker_code else null end,
    lease_expire_at = case when #{partitionStatus} = #{runningStatus} then lease_expire_at else null end,
    current_invocation_id = case when #{partitionStatus} = #{runningStatus} then current_invocation_id else null end,
    invocation_started_at = case when #{partitionStatus} = #{runningStatus} then invocation_started_at else null end,
    finished_at = case
        when #{partitionStatus} in (#{terminalStatus1}, #{terminalStatus2}, #{terminalStatus3}, #{terminalStatus4}) then #{finishedAt}
        else finished_at
    end,
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and version = #{expectedVersion}
  and partition_status not in (#{terminalStatus1}, #{terminalStatus2}, #{terminalStatus3}, #{terminalStatus4})

mapper.select:
select p.*
from batch.job_partition p
where p.partition_status = #{readyStatus}
  and p.lease_expire_at is null
  and exists (
    select 1 from batch.job_task t
    where t.tenant_id = p.tenant_id
      and t.job_partition_id = p.id
      and t.task_status = #{runningTaskStatus}
  )
  and p.updated_at < #{olderThan}
order by p.id asc
limit #{batchSize}

select *
from batch.job_partition
where partition_status = #{waitingStatus}
order by id asc
limit #{batchSize}

mapper.update:
update batch.job_partition
set partition_status = #{toStatus},
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and partition_status = #{fromStatus}
  and version = #{expectedVersion}

